#include <vector>

using namespace std;

long long solve(std::string s) {
    int n = s.size();
    vector<int> c_count(n + 1, 0);
    vector<int> t_count(n + 1, 0);

    // Precompute the number of 'C's after each position
    for (int i = n - 1; i >= 0; --i) {
        c_count[i] = c_count[i + 1] + (s[i] == 'C' ? 1 : 0);
    }

    // Precompute the number of 'T's after each position
    for (int i = n - 1; i >= 0; --i) {
        t_count[i] = t_count[i + 1] + (s[i] == 'T' ? 1 : 0);
    }

    long long original = 0;
    long long max_increase = 0;
    int l_count = 0;

    for (int i = 0; i < n; ++i) {
        if (s[i] == 'L') {
            l_count++;
            original += (long long)c_count[i] * t_count[i];
        }
    }

    if (l_count == 0) {
        // No 'L's, inserting 'L' can potentially create new LCTs
        for (int i = 0; i <= n; ++i) {
            long long c = c_count[i];
            long long t = t_count[i];
            max_increase = max(max_increase, c * t);
        }
        return max_increase;
    }

    // Check inserting 'L' at each position
    for (int i = 0; i <= n; ++i) {
        long long left_l = 0;
        for (int j = 0; j < i; ++j) {
            if (s[j] == 'L') left_l++;
        }
        long long c = c_count[i];
        long long t = t_count[i];
        long long increase = left_l * (c * t) + (l_count - left_l) * (c * t);
        max_increase = max(max_increase, increase);
    }

    // Check inserting 'C' at each position
    for (int i = 0; i <= n; ++i) {
        long long l = 0;
        long long c_after = c_count[i];
        long long t_after = t_count[i];
        for (int j = 0; j < i; ++j) {
            if (s[j] == 'L') l++;
        }
        long long increase = l * (t_after);
        max_increase = max(max_increase, increase);
    }

    // Check inserting 'T' at each position
    for (int i = 0; i <= n; ++i) {
        long long l = 0;
        long long c = 0;
        for (int j = 0; j < i; ++j) {
            if (s[j] == 'L') l++;
            if (s[j] == 'C') c++;
        }
        long long increase = l * c;
        max_increase = max(max_increase, increase);
    }

    return original + max_increase;
}

